import React, {
  createContext,
  useState,
  useContext,
  useEffect
} from 'react';

import * as userService from '../services/userService';
import { useAuth } from './AuthContext';
import toast from 'react-hot-toast';

const CartContext = createContext();

export const useCart = () => {
  const context = useContext(CartContext);

  if (!context) {
    throw new Error('useCart must be used within CartProvider');
  }

  return context;
};

export const CartProvider = ({ children }) => {

  const {
    isAuthenticated,
    loading: authLoading
  } = useAuth();

  const [cart, setCart] = useState([]);
  const [loading, setLoading] = useState(true);

  // ============================
  // Init Cart After Auth Ready
  // ============================
  useEffect(() => {

    if (authLoading) return;

    initializeCart();

  }, [isAuthenticated, authLoading]);

  // ============================
  // Main Init
  // ============================
  const initializeCart = async () => {

    setLoading(true);

    try {

      const localCart =
        JSON.parse(localStorage.getItem('cart') || '[]');

      // User Logged In
      if (isAuthenticated) {

        // Sync guest cart first
        if (localCart.length > 0) {
          await syncLocalCartToServer(localCart);
          localStorage.removeItem('cart');
        }

        const res = await userService.getCart();
        setCart(res || []);

      }

      // Guest
      else {
        setCart(localCart);
      }

    } catch (err) {
      console.error('Cart init error:', err);
    } finally {
      setLoading(false);
    }
  };

  // ============================
  // Sync Guest → Server
  // ============================
  const syncLocalCartToServer = async (localCart) => {

    try {

      for (const item of localCart) {

        await userService.addToCart(
          item.product._id,
          item.quantity
        );
      }

    } catch (err) {
      console.error('Cart sync failed:', err);
    }
  };

  // ============================
  // Save Local Cart
  // ============================
  const persistLocalCart = (data) => {
    localStorage.setItem('cart', JSON.stringify(data));
  };

  // ============================
  // Add
  // ============================
  const addToCart = async (product, quantity = 1) => {

    try {

      if (isAuthenticated) {

        const res = await userService.addToCart(
          product._id,
          quantity
        );

        setCart(res);

      } else {

        const updated = [...cart];

        const existing = updated.find(
          i => i.product._id === product._id
        );

        if (existing) {
          existing.quantity += quantity;
        } else {
          updated.push({
            product,
            quantity
          });
        }

        setCart(updated);
        persistLocalCart(updated);
      }

      toast.success('Added to cart');

    } catch (err) {
      console.error(err);
      toast.error('Add to cart failed');
    }
  };

  // ============================
  // Update
  // ============================
  const updateQuantity = async (productId, quantity) => {

    if (quantity < 1) {
      return removeFromCart(productId);
    }

    try {

      if (isAuthenticated) {

        const res =
          await userService.updateCartItem(
            productId,
            quantity
          );

        setCart(res);

      } else {

        const updated = cart.map(item =>
          item.product._id === productId
            ? { ...item, quantity }
            : item
        );

        setCart(updated);
        persistLocalCart(updated);
      }

    } catch (err) {
      toast.error('Update failed');
    }
  };

  // ============================
  // Remove
  // ============================
  const removeFromCart = async (productId) => {

    try {

      if (isAuthenticated) {

        const res =
          await userService.removeFromCart(productId);

        setCart(res);

      } else {

        const updated =
          cart.filter(i => i.product._id !== productId);

        setCart(updated);
        persistLocalCart(updated);
      }

      toast.success('Removed');

    } catch (err) {
      toast.error('Remove failed');
    }
  };

  // ============================
  // Clear
  // ============================
  const clearCart = async () => {

    try {

      if (isAuthenticated) {
        await userService.clearCart();
      }

      setCart([]);
      localStorage.removeItem('cart');

    } catch (err) {
      console.error(err);
    }
  };

  // ============================
  // Helpers
  // ============================
 const getCartTotal = () =>
  cart.reduce(
    (t, i) => t + (i.product?.price || 0) * i.quantity,
    0
  );


  const getCartCount = () =>
    cart.reduce((c, i) => c + i.quantity, 0);

  // ============================
  // UI Loader
  // ============================
  if (loading) {
    return <div>Loading cart...</div>;
  }

  return (
    <CartContext.Provider
      value={{
        cart,
        loading,

        addToCart,
        updateQuantity,
        removeFromCart,
        clearCart,

        getCartTotal,
        getCartCount
      }}
    >
      {children}
    </CartContext.Provider>
  );
};
